from collections import defaultdict

counts = defaultdict(int)        # missing -> 0
for ch in 'aab':
    counts[ch] += 1              # no .get
print(dict(counts))             # {'a': 2, 'b': 1}

groups = defaultdict(list)       # missing -> []
for w in ['ant', 'ax', 'be']:
    groups[w[0]].append(w)      # no .setdefault
print(dict(groups))             # {'a': ['ant', 'ax'], 'b': ['be']}

